CREATE TYPE user_role AS ENUM ('customer', 'food_place', 'rider');
CREATE TYPE order_status AS ENUM ('placed', 'accepted', 'cooking', 'ready_for_pickup', 'picked_up', 'arrived', 'delivered', 'cancelled');
CREATE TABLE profiles (id UUID REFERENCES auth.users(id) ON DELETE CASCADE PRIMARY KEY, full_name TEXT NOT NULL, email TEXT UNIQUE NOT NULL, phone TEXT NOT NULL, role user_role NOT NULL, avatar_url TEXT, created_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE food_places (id UUID DEFAULT gen_random_uuid() PRIMARY KEY, owner_id UUID REFERENCES profiles(id) ON DELETE CASCADE NOT NULL, name TEXT NOT NULL, description TEXT, image_url TEXT, address TEXT, is_active BOOLEAN DEFAULT TRUE, created_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE menu_items (id UUID DEFAULT gen_random_uuid() PRIMARY KEY, food_place_id UUID REFERENCES food_places(id) ON DELETE CASCADE NOT NULL, name TEXT NOT NULL, description TEXT, price NUMERIC NOT NULL, image_url TEXT, is_available BOOLEAN DEFAULT TRUE, category TEXT, created_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE orders (id UUID DEFAULT gen_random_uuid() PRIMARY KEY, customer_id UUID REFERENCES profiles(id) NOT NULL, food_place_id UUID REFERENCES food_places(id) NOT NULL, rider_id UUID REFERENCES profiles(id), total_amount NUMERIC NOT NULL, status order_status DEFAULT 'placed' NOT NULL, delivery_address TEXT NOT NULL, rider_lat FLOAT8, rider_lng FLOAT8, payment_status TEXT DEFAULT 'pending', created_at TIMESTAMPTZ DEFAULT NOW(), updated_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE order_items (id UUID DEFAULT gen_random_uuid() PRIMARY KEY, order_id UUID REFERENCES orders(id) ON DELETE CASCADE NOT NULL, menu_item_id UUID REFERENCES menu_items(id) NOT NULL, item_name TEXT NOT NULL, item_price NUMERIC NOT NULL, quantity INT NOT NULL DEFAULT 1);
CREATE TABLE notifications (id UUID DEFAULT gen_random_uuid() PRIMARY KEY, user_id UUID REFERENCES profiles(id) ON DELETE CASCADE NOT NULL, title TEXT NOT NULL, message TEXT NOT NULL, is_read BOOLEAN DEFAULT FALSE, type TEXT, created_at TIMESTAMPTZ DEFAULT NOW());
